// // This module decodes a 2-bit input to a 4-bit output only when the enable signal is LOW.
module binary_decoder(
    input      en      ,
    input      [1:0] in,

    output reg [3:0] out
);

always @(*) begin
    if (en) begin
        case(in)
            2'b00: out = 4'b0001;
            2'b01: out = 4'b0010;
            2'b10: out = 4'b0100;
            2'b11: out = 4'b1000;
            default: out = 4'b0000;
        endcase
    end else begin
        out = 4'b0000;
    end
end

endmodule
